  `the_order` smallint(6) NOT NULL DEFAULT 1 COMMENT '排序号',
  `child_num` smallint(6) NOT NULL DEFAULT 0 COMMENT '孩子节点数量',
  `IS_LEAF` bit(1) NULL DEFAULT b'0' COMMENT '是否是叶子节点',
  `PARENT_ID` int(11) NULL DEFAULT 0 COMMENT '父节点编号 默认 是 0 ',
  `the_level` smallint(6) NOT NULL DEFAULT 1 COMMENT '等级号',
  `CREATE_TIME` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
