  `department_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '电话',
  `department_postal_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '邮政编码',
  `AREA_ID` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '外键,关联表 10',
  `MAJOR_ID` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '外码 (关联表 6, 如果当前节点表示班级, 否则为 0)',
  `START_YEAR` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '入学年份, 班级需要, 否则为空',
  `type_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '外码 (关联表25)',
  PRIMARY KEY (`ID`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 155 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

