-- ----------------------------
DROP TABLE IF EXISTS `internship_grade_config_item`;
CREATE TABLE `internship_grade_config_item`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `internship_id` int(10) UNSIGNED NOT NULL COMMENT '关联 BaseInternship.id（实习项目）',
  `level_order` int(10) UNSIGNED NOT NULL COMMENT '由第几级审核人打分，对应业务实体 verifyFirstRoleId..verifyFifthRoleId，取值 [1,5]',
  `max_score` decimal(5, 2) NOT NULL DEFAULT 100.00 COMMENT '满分',
  `source_table` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '评分目标业务表名，如 MainDiary',
  `version` int(11) NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `weight` decimal(5, 2) NOT NULL COMMENT '占比 0-100',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

