-- ----------------------------
-- Table structure for main_diary
-- ----------------------------
DROP TABLE IF EXISTS `main_diary`;
CREATE TABLE `main_diary`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `content` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '日记文字内容',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编码',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `remarks` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `current_verify_type_id` int(11) NULL DEFAULT 1 COMMENT '流程当前处在的审核级别id',
  `period_id` int(10) UNSIGNED NOT NULL COMMENT '外键，关联表34（MainDiaryPeriod）',
  `relation_id` int(10) UNSIGNED NOT NULL COMMENT '关联记录ID，外键，RelStuInternshipPost(校外)或RelTitleStudent(校内)',
  `submit` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否已提交：1=已提交，0=未提交',
  `table_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '关联表名：RelStuInternshipPost（校外）或 RelTitleStudent（校内）',
  `verify_fifth_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第五轮审核角色id，外键，关联表SysRole',
  `verify_first_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第一轮审核角色id，外键，关联表SysRole',
  `verify_fourth_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第四轮审核角色id，外键，关联表SysRole',
  `verify_second_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第二轮审核角色id，外键，关联表SysRole',
  `verify_third_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第三轮审核角色id，外键，关联表SysRole',
  `verify_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '验证类型id，外键，关联表BaseVerifyType',
  `title` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '日志标题',
  `is_active` tinyint(4) GENERATED ALWAYS AS (if((`is_deleted` = 0x00),1,NULL)) VIRTUAL NULL,
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `score_detail` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '评分明细 JSON 快照：[{levelOrder,itemName,weight,maxScore,score,verifyUserId,verifyUserName}]',
  `total_score` decimal(5, 2) NULL DEFAULT NULL COMMENT '总成绩；最后一级 PASS 时由后端按 grade_config 加权汇总写入，老数据为 null',
  `total_score_lock_time` datetime NULL DEFAULT NULL COMMENT '总成绩物化时间',
  `ai_review_comment` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT 'AI批改意见（对应 Coze output）',
  `ai_review_raw` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT 'AI批改原始响应，便于排错',
  `ai_review_score` decimal(5, 2) NULL DEFAULT NULL COMMENT 'AI批改分数（对应 Coze score）',
  `ai_review_status` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'AI批改状态：PENDING/RUNNING/SUCCESS/FAILED',
  `ai_review_time` datetime NULL DEFAULT NULL COMMENT 'AI批改完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_diary_period_active`(`relation_id`, `table_name`, `period_id`, `is_active`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 231 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

