  `begin_time` datetime NOT NULL COMMENT '该期开始时间',
  `end_time` datetime NOT NULL COMMENT '该期结束时间',
  `internship_id` int(10) UNSIGNED NOT NULL COMMENT '外键，关联表16（MainInternship）',
  `period_index` int(10) UNSIGNED NOT NULL COMMENT '期数（第几期，1-based）',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 216 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of main_diary_period
-- ----------------------------

-- ----------------------------
-- Table structure for main_diary_score_detail
-- ----------------------------
DROP TABLE IF EXISTS `main_diary_score_detail`;
CREATE TABLE `main_diary_score_detail`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `diary_id` int(10) UNSIGNED NOT NULL COMMENT '关联日志ID，MainDiary.id',
  `level_order` int(10) UNSIGNED NOT NULL COMMENT '审核级别序号 [1,5]',
  `weight` decimal(5, 2) NOT NULL COMMENT '权重占比 0-100',
  `max_score` decimal(5, 2) NOT NULL DEFAULT 100.00 COMMENT '满分',
  `score` decimal(5, 2) NULL DEFAULT NULL COMMENT '审核人实际给分',
  `verify_user_id` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核人用户ID',
  `verify_user_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核人姓名',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_diary_id`(`diary_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '实习日志评分明细' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of main_diary_score_detail
-- ----------------------------

-- ----------------------------
-- Table structure for main_enterprise_info
-- ----------------------------
DROP TABLE IF EXISTS `main_enterprise_info`;
CREATE TABLE `main_enterprise_info`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_deleted` bit(1) NOT NULL DEFAULT b'0',
  `company_id` int(10) UNSIGNED NOT NULL COMMENT 'company department id',
  `school_id` int(10) UNSIGNED NOT NULL COMMENT 'school root department id',
  `admin_user_id` int(10) UNSIGNED NOT NULL COMMENT 'company admin user id',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'unified social credit code, synced to base_department.code when approved',
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'company name snapshot',
  `contact_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'contact person',
  `contact_phone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'contact phone',
  `contact_email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'contact email',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'company address',
  `legal_person` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'legal person',
  `industry` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'industry',
  `company_scale` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'company scale',
  `business_scope` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'business scope',
  `introduction` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'company introduction',
  `remarks` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'remarks or audit note',
  `verify_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT 'verify type id',
  `verify_first_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'first verify role id',
  `verify_second_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'second verify role id',
  `verify_third_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'third verify role id',
  `verify_fourth_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'fourth verify role id',
  `verify_fifth_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'fifth verify role id',
  `audit_status` tinyint(4) NOT NULL DEFAULT -1 COMMENT '-1 draft, 0 pending, 1 approved, 2 rejected, 3 returned',
  `current_verify_type_id` int(11) NULL DEFAULT 1 COMMENT 'current verify level',
  `is_current` bit(1) NOT NULL DEFAULT b'0' COMMENT 'whether this version is current approved version',
  `version_no` int(10) UNSIGNED NOT NULL DEFAULT 1 COMMENT 'version number inside same company',
  `approved_time` datetime NULL DEFAULT NULL COMMENT 'approved time',
  `approved_by` int(10) UNSIGNED NULL DEFAULT NULL COMMENT 'final approver user id',
  `version` int(11) NULL DEFAULT 0 COMMENT 'optimistic lock version',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_main_enterprise_company_version`(`company_id`, `version_no`) USING BTREE,
  INDEX `idx_main_enterprise_info_company`(`company_id`, `is_deleted`) USING BTREE,
  INDEX `idx_main_enterprise_info_school_status`(`school_id`, `audit_status`, `is_deleted`) USING BTREE,
  INDEX `idx_main_enterprise_info_current`(`company_id`, `is_current`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 23 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'enterprise info declaration and audit' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of main_enterprise_info
-- ----------------------------

-- ----------------------------
-- Table structure for main_internship
-- ----------------------------
DROP TABLE IF EXISTS `main_internship`;
CREATE TABLE `main_internship`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编码',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `remarks` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `creator_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '创建人id',
  `cron` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实习报告周期（cron 表达式，如 DAILY/WEEKLY/MONTHLY）',
  `internship_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '实习类型',
  `student_num` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '学生人数',
  `the_order` smallint(6) NOT NULL DEFAULT 1 COMMENT '排序号',
  `current_verify_type_id` int(10) NULL DEFAULT NULL COMMENT '当前处在的审核级别',
  `report_end_time` datetime NULL DEFAULT NULL COMMENT '实习上报结束时间',
  `report_start_time` datetime NULL DEFAULT NULL COMMENT '实习上报开始时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 209 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

