  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编码',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `remarks` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `all_person_num` int(11) NULL DEFAULT 0 COMMENT '岗位人数',
  `now_person_num` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '已选人数',
  `internship_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '实习项目id，外键，关联表MainInternship',
  `post_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '岗位类型id,外键，关联表BasePostType',
  `the_order` smallint(6) NOT NULL DEFAULT 1 COMMENT '排序号',
  `base_post_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '岗位类型id,外键，关联表BasePostType',
  `main_internship_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '实习项目id，外键，关联表MainInternship',
  `current_verify_type_id` int(11) NULL DEFAULT 1 COMMENT '当前处在的审核级别',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 143 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

