-- ----------------------------
-- Table structure for main_internship_termination
-- ----------------------------
DROP TABLE IF EXISTS `main_internship_termination`;
CREATE TABLE `main_internship_termination`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `verify_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '审核类型',
  `verify_fifth_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第五级审核角色',
  `verify_first_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第一级审核角色',
  `verify_fourth_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第四级审核角色',
  `verify_second_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第二级审核角色',
  `verify_third_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第三级审核角色',
  `internship_id` int(10) UNSIGNED NOT NULL COMMENT '实习项目ID',
  `student_id` int(10) UNSIGNED NOT NULL COMMENT '学生ID',
  `relation_table` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT 'RelStuInternshipPost or RelTitleStudent',
  `relation_id` int(10) UNSIGNED NOT NULL COMMENT '实习关系ID',
  `terminate_date` datetime NULL DEFAULT NULL COMMENT '终止日期',
  `reason_type` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'termination reason type',
  `reason` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'termination reason',
  `attachment_ids` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件ID，逗号分隔',
  `apply_user_id` int(10) UNSIGNED NOT NULL COMMENT '发起人ID',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0 pending, 1 approved, 2 rejected, 3 returned, 4 cancelled',
  `current_verify_type_id` int(11) NULL DEFAULT 1 COMMENT '当前审核级别',
  `approved_time` datetime NULL DEFAULT NULL COMMENT '通过时间',
  `approved_by` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '最终审核人',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_mit_relation_status`(`relation_table`, `relation_id`, `status`, `is_deleted`) USING BTREE,
  INDEX `idx_mit_internship_student`(`internship_id`, `student_id`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '终止学生实习申请' ROW_FORMAT = DYNAMIC;

