  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `verify_fifth_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第五轮审核的人物角色id，外键，关联表SysRole',
  `verify_first_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第一轮审核的人物角色id，外键，关联表SysRole',
  `verify_fourth_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第四轮审核的人物角色id，外键，关联表SysRole',
  `verify_second_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第二轮审核的人物角色id，外键，关联表SysRole',
  `verify_third_role_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '第三轮审核的人物角色id，外键，关联表SysRole',
  `verify_type_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '验证类型id，外键，关联表BaseVerifyType',
  `current_verify_type_id` int(11) NULL DEFAULT 1 COMMENT '流程当前处在的审核级别id',
  `end_time` datetime NOT NULL COMMENT '请假结束时间',
  `remarks` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '请假备注/审核意见',
  `start_time` datetime NOT NULL COMMENT '请假开始时间',
  `stu_internship_id` int(10) UNSIGNED NOT NULL COMMENT '关联记录ID：校外=rel_stu_internship_post.id，校内=rel_title_student.id',
  `version` int(11) NULL DEFAULT 0 COMMENT '乐观锁版本号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

