-- ----------------------------
-- Table structure for main_verify_process
-- ----------------------------
DROP TABLE IF EXISTS `main_verify_process`;
CREATE TABLE `main_verify_process`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_user_id` int(10) UNSIGNED NOT NULL COMMENT '外键，关联表 1，当前流程创建人',
  `is_audit` smallint(6) NOT NULL COMMENT '是否审核：-1-保存未提交，0-未审核，1-审核通过，2-审核退回',
  `reason` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '审核理由',
  `relation_id` int(10) UNSIGNED NOT NULL COMMENT '外键，关联表 11、15、20、21、22、23',
  `table_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '当前审核操作表名（例如 MainDairy）',
  `verify_user_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '审核用户id，格式：12|14|17',
  `process_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '外键,关联表 20',
  `score` decimal(5, 2) NULL DEFAULT NULL COMMENT '该级评分；该级若有 grade_config 配置且本行 PASS 时由审核接口写入，否则为 null',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_mvp_table_relation`(`table_name`, `relation_id`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2550 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

