  `verify_fifth_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '第五轮审核的人物角色id，外键，关联表SysRole',
  `verify_first_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '第一轮审核的人物角色id，外键，关联表SysRole',
  `verify_fourth_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '第轮审核的人物角色id，外键，关联表SysRole',
  `verify_second_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '第二轮审核的人物角色id，外键，关联表SysRole',
  `verify_third_role_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '第三轮审核的人物角色id，外键，关联表SysRole',
  `end_time` datetime NULL DEFAULT NULL COMMENT '流程结束时间',
  `start_time` datetime NULL DEFAULT NULL COMMENT '流程开始时间',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编码',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
