  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '编号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编码',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `remarks` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `current_verify_type_id` int(11) NULL DEFAULT 1 COMMENT '当前处在的审核级别',
  `stu_id` int(10) UNSIGNED NOT NULL COMMENT '外键，关联表1（学生）',
  `title_id` int(10) UNSIGNED NOT NULL COMMENT '外键，关联表32（导师题目）',
  `topic_reasons` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '选题理由',
  `is_active` tinyint(4) GENERATED ALWAYS AS (if((`is_deleted` = 0x00),1,NULL)) VIRTUAL NULL,
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `confirmed_by` int(10) UNSIGNED NULL DEFAULT NULL COMMENT 'final confirmer user id',
  `confirmed_time` datetime NULL DEFAULT NULL COMMENT 'final confirmation time',
  `internship_id` int(10) UNSIGNED NULL DEFAULT NULL COMMENT 'denormalized internship id from RelTitleTeacher',
  `is_final` tinyint(4) NOT NULL DEFAULT 0 COMMENT 'whether this row is the final title assignment',
  `source_type` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT 'STUDENT_CANDIDATE' COMMENT 'source of title selection',
  `internship_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT 'internship status: 0 active, 1 terminating, 2 terminated',
  `termination_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '终止申请ID',
  `terminated_time` datetime NULL DEFAULT NULL COMMENT '终止通过时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_title_stu_active`(`title_id`, `stu_id`, `is_active`) USING BTREE,
  INDEX `idx_rts_title_id`(`title_id`, `is_deleted`) USING BTREE,
  INDEX `idx_rts_stu_id`(`stu_id`, `is_deleted`) USING BTREE,
  INDEX `idx_rts_termination_status`(`internship_status`, `termination_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 169 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

