-- ----------------------------

-- View structure for view_base_department
-- ----------------------------
DROP VIEW IF EXISTS `view_base_department`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_base_department` AS select `base_department`.`ID` AS `id`,`base_department`.`IS_DELETED` AS `is_deleted`,`base_department`.`code` AS `code`,`base_department`.`name` AS `name`,`base_department`.`remarks` AS `remarks`,`base_department`.`the_order` AS `the_order`,`base_department`.`child_num` AS `child_num`,`base_department`.`IS_LEAF` AS `is_leaf`,`base_department`.`PARENT_ID` AS `parent_id`,`base_department`.`the_level` AS `the_level`,`base_department`.`CREATE_TIME` AS `create_time`,`base_department`.`UPDATE_TIME` AS `update_time`,`base_department`.`DEPARTMENT_ADD` AS `department_add`,`base_department`.`department_email` AS `department_email`,`base_department`.`department_fax` AS `department_fax`,`base_department`.`department_phone` AS `department_phone`,`base_department`.`department_postal_code` AS `department_postal_code`,`base_department`.`AREA_ID` AS `area_id`,`base_department`.`MAJOR_ID` AS `major_id`,`base_department`.`START_YEAR` AS `start_year`,`base_major`.`name` AS `major_name`,`sys_area`.`name` AS `area_name`,`base_department`.`type_id` AS `type_id`,`base_depart_type`.`name` AS `type_name`,`base_depart_type`.`code` AS `type_code`,`department_getSchoolId`(`base_department`.`ID`) AS `SCHOOL_ID` from (((`base_department` left join `base_major` on((`base_department`.`MAJOR_ID` = `base_major`.`ID`))) left join `sys_area` on((`base_department`.`AREA_ID` = `sys_area`.`ID`))) left join `base_depart_type` on((`base_department`.`type_id` = `base_depart_type`.`id`)));

-- ----------------------------
-- View structure for view_base_internship_type
-- ----------------------------
DROP VIEW IF EXISTS `view_base_internship_type`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_base_internship_type` AS select `base_internship_type`.`id` AS `id`,`base_internship_type`.`create_time` AS `create_time`,`base_internship_type`.`is_deleted` AS `is_deleted`,`base_internship_type`.`update_time` AS `update_time`,`base_internship_type`.`code` AS `code`,`base_internship_type`.`name` AS `name`,`base_internship_type`.`remarks` AS `remarks`,`base_internship_type`.`university_id` AS `university_id`,`base_internship_type`.`int_type_id` AS `int_type_id`,`department_getAllParentNames`(`base_internship_type`.`university_id`) AS `university_name`,`base_int_type`.`name` AS `type_name` from ((`base_internship_type` left join `base_department` `d` on((`base_internship_type`.`university_id` = `d`.`ID`))) join `base_int_type` on((`base_internship_type`.`int_type_id` = `base_int_type`.`id`)));

-- ----------------------------
-- View structure for view_base_post_type
-- ----------------------------
DROP VIEW IF EXISTS `view_base_post_type`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_base_post_type` AS select `base_post_type`.`ID` AS `ID`,`base_post_type`.`CREATE_TIME` AS `CREATE_TIME`,`base_post_type`.`IS_DELETED` AS `IS_DELETED`,`base_post_type`.`UPDATE_TIME` AS `UPDATE_TIME`,`base_post_type`.`code` AS `CODE`,`base_post_type`.`name` AS `NAME`,`base_post_type`.`remarks` AS `REMARKS`,`base_post_type`.`the_order` AS `THE_ORDER`,`base_post_type`.`ADDRESS` AS `ADDRESS`,`base_post_type`.`COMPANY_ID` AS `COMPANY_ID`,`base_post_type`.`SALARY` AS `SALARY`,`base_department`.`name` AS `DEPARTMENT_NAME`,`base_department`.`type_id` AS `TYPE_ID`,ifnull(group_concat(distinct `rel_post_major`.`major_id` separator '|'),'') AS `major_ids`,ifnull(group_concat(distinct `base_major`.`name` separator ','),'') AS `major_names` from (((`base_post_type` join `base_department` on((`base_post_type`.`COMPANY_ID` = `base_department`.`ID`))) left join `rel_post_major` on((`rel_post_major`.`post_type_id` = `base_post_type`.`ID`))) left join `base_major` on((`rel_post_major`.`major_id` = `base_major`.`ID`))) group by `base_post_type`.`ID`,`base_post_type`.`CREATE_TIME`,`base_post_type`.`IS_DELETED`,`base_post_type`.`UPDATE_TIME`,`base_post_type`.`code`,`base_post_type`.`name`,`base_post_type`.`remarks`,`base_post_type`.`the_order`,`base_post_type`.`ADDRESS`,`base_post_type`.`COMPANY_ID`,`base_post_type`.`SALARY`,`base_department`.`name`,`base_department`.`type_id`;

-- ----------------------------
-- View structure for view_base_user
-- ----------------------------
DROP VIEW IF EXISTS `view_base_user`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_base_user` AS select `u`.`address` AS `ADDRESS`,`u`.`BIRTH` AS `BIRTH`,`u`.`DEPARTMENT_ID` AS `DEPARTMENT_ID`,`u`.`email` AS `EMAIL`,`u`.`FIRST_LOGIN` AS `FIRST_LOGIN`,`u`.`id_card` AS `ID_CARD`,`u`.`JOB_ID` AS `JOB_ID`,`u`.`name` AS `NAME`,`u`.`ID` AS `ID`,`u`.`IS_DELETED` AS `IS_DELETED`,`u`.`nick_name` AS `NICK_NAME`,`u`.`password` AS `PASSWORD`,`u`.`phone` AS `PHONE`,`u`.`postal_code` AS `POSTAL_CODE`,`u`.`REGISTER_TIME` AS `REGISTER_TIME`,`u`.`remarks` AS `REMARKS`,`u`.`sex` AS `SEX`,`u`.`theme_color` AS `THEME_COLOR`,`u`.`work_id` AS `WORK_ID`,`u`.`account` AS `ACCOUNT`,`u`.`CREATE_TIME` AS `CREATE_TIME`,`u`.`UPDATE_TIME` AS `UPDATE_TIME`,`p`.`name` AS `JOB_NAME`,`department_getAllParentNames`(`u`.`DEPARTMENT_ID`) AS `DEPARTMENT_NAME`,`department_getSchoolId`(`u`.`DEPARTMENT_ID`) AS `SCHOOL_ID`,`u`.`code` AS `CODE`,`u`.`major_id` AS `major_id`,`p`.`code` AS `job_code`,`u`.`end_year` AS `end_year`,`u`.`school_length` AS `school_length`,`u`.`start_year` AS `start_year` from ((`base_user` `u` left join `base_department` `d` on((`u`.`DEPARTMENT_ID` = `d`.`ID`))) left join `base_job_position` `p` on((`u`.`JOB_ID` = `p`.`ID`)));

-- ----------------------------
-- View structure for view_base_user_internship
-- ----------------------------
DROP VIEW IF EXISTS `view_base_user_internship`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_base_user_internship` AS select `bu`.`ID` AS `ID`,`bu`.`IS_DELETED` AS `IS_DELETED`,`bu`.`address` AS `address`,`bu`.`BIRTH` AS `BIRTH`,`bu`.`DEPARTMENT_ID` AS `DEPARTMENT_ID`,`bu`.`email` AS `email`,`bu`.`FIRST_LOGIN` AS `FIRST_LOGIN`,`bu`.`id_card` AS `id_card`,`bu`.`JOB_ID` AS `JOB_ID`,`bu`.`name` AS `name`,`bu`.`nick_name` AS `nick_name`,`bu`.`password` AS `password`,`bu`.`phone` AS `phone`,`bu`.`postal_code` AS `postal_code`,`bu`.`REGISTER_TIME` AS `REGISTER_TIME`,`bu`.`remarks` AS `remarks`,`bu`.`sex` AS `sex`,`bu`.`theme_color` AS `theme_color`,`bu`.`work_id` AS `work_id`,`bu`.`account` AS `account`,`bu`.`CREATE_TIME` AS `CREATE_TIME`,`bu`.`UPDATE_TIME` AS `UPDATE_TIME`,`bu`.`code` AS `code`,`bu`.`major_id` AS `major_id` from `base_user` `bu` where (not(exists(select 1 from `rel_intership_user` `riu` where (`riu`.`user_id` = `bu`.`ID`))));

-- ----------------------------
-- View structure for view_leave_audit_flow
-- ----------------------------
DROP VIEW IF EXISTS `view_leave_audit_flow`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_leave_audit_flow` AS select `mvp`.`id` AS `id`,`ml`.`id` AS `leave_id`,`mvp`.`id` AS `verify_process_id`,`mvp`.`create_time` AS `create_time`,`mvp`.`update_time` AS `update_time`,`mvp`.`is_deleted` AS `is_deleted`,`mvp`.`relation_id` AS `relation_id`,`mvp`.`process_id` AS `process_id`,`mvp`.`create_user_id` AS `create_user_id`,`mvp`.`verify_user_id` AS `verify_user_id`,`mvp`.`is_audit` AS `is_audit`,`mvp`.`reason` AS `reason`,`mvp`.`table_name` AS `table_name`,`ml`.`current_verify_type_id` AS `current_verify_type_id`,`bvt`.`id` AS `verify_type_id`,`bvt`.`name` AS `verify_type_name`,`bvt`.`the_order` AS `verify_type_order`,(`ml`.`current_verify_type_id` + 1) AS `next_verify_level` from ((`main_verify_process` `mvp` join `main_leave` `ml` on(((`ml`.`id` = `mvp`.`relation_id`) and (`ml`.`is_deleted` = 0x00)))) left join `base_verify_type` `bvt` on(((`bvt`.`id` = `ml`.`current_verify_type_id`) and (`bvt`.`is_deleted` = 0x00)))) where ((`mvp`.`table_name` = 'MainLeave') and (`mvp`.`is_deleted` = 0x00));

-- ----------------------------
-- View structure for view_leave_universal_details
-- ----------------------------
DROP VIEW IF EXISTS `view_leave_universal_details`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_leave_universal_details` AS select `ml`.`id` AS `id`,`ml`.`id` AS `leave_id`,`ml`.`create_time` AS `create_time`,`ml`.`update_time` AS `update_time`,`ml`.`is_deleted` AS `is_deleted`,`ml`.`stu_internship_id` AS `stu_internship_id`,`ml`.`start_time` AS `start_time`,`ml`.`end_time` AS `end_time`,`ml`.`remarks` AS `remarks`,coalesce(`rsp`.`student_id`,`rts`.`stu_id`) AS `student_id`,`stu`.`name` AS `student_name`,`stu`.`account` AS `student_account`,(case when (`rsp`.`id` is not null) then 'EXTERNAL' when (`rts`.`id` is not null) then 'INTERNAL' else 'UNKNOWN' end) AS `internship_mode`,coalesce(`ext_ts`.`teacher_id`,`rtt`.`teacher_id`) AS `teacher_id`,`tea`.`name` AS `teacher_name`,(case when (`rsp`.`id` is not null) then 'RelStuInternshipPost' when (`rts`.`id` is not null) then 'RelTitleStudent' else NULL end) AS `relation_table` from ((((((`main_leave` `ml` left join `rel_stu_internship_post` `rsp` on(((`rsp`.`id` = `ml`.`stu_internship_id`) and (`rsp`.`is_deleted` = 0x00)))) left join `rel_teacher_student` `ext_ts` on(((`ext_ts`.`rel_internship_id` = `rsp`.`id`) and (`ext_ts`.`is_deleted` = 0x00)))) left join `rel_title_student` `rts` on(((`rts`.`id` = `ml`.`stu_internship_id`) and (`rts`.`is_deleted` = 0x00)))) left join `rel_title_teacher` `rtt` on(((`rtt`.`id` = `rts`.`title_id`) and (`rtt`.`is_deleted` = 0x00)))) left join `base_user` `stu` on(((`stu`.`ID` = coalesce(`rsp`.`student_id`,`rts`.`stu_id`)) and (`stu`.`IS_DELETED` = 0x00)))) left join `base_user` `tea` on(((`tea`.`ID` = coalesce(`ext_ts`.`teacher_id`,`rtt`.`teacher_id`)) and (`tea`.`IS_DELETED` = 0x00)))) where (`ml`.`is_deleted` = 0x00);

-- ----------------------------
-- View structure for view_main_internship
