CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_verify_main_diary_merge` AS select `mvp`.`id` AS `id`,`mvp`.`create_time` AS `create_time`,`mvp`.`is_deleted` AS `is_deleted`,`mvp`.`update_time` AS `update_time`,`mvp`.`relation_id` AS `relation_id`,`mvp`.`create_user_id` AS `create_user_id`,`mvp`.`verify_user_id` AS `verify_user_id`,`mvp`.`is_audit` AS `is_audit`,`mvp`.`reason` AS `reason`,`mvp`.`table_name` AS `table_name`,(select group_concat(`bu`.`name` separator '，') from `internship`.`base_user` `bu` where (find_in_set(`bu`.`ID`,replace(`mvp`.`verify_user_id`,'|',',')) > 0)) AS `verify_user_name`,`bu_create`.`name` AS `create_user_name`,`vmd`.`verify_type_id` AS `verify_type_id`,`vmd`.`verify_first_role_id` AS `verify_first_role_id`,`vmd`.`verify_second_role_id` AS `verify_second_role_id`,`vmd`.`verify_third_role_id` AS `verify_third_role_id`,`vmd`.`verify_fourth_role_id` AS `verify_fourth_role_id`,`vmd`.`verify_fifth_role_id` AS `verify_fifth_role_id`,`vmd`.`current_verify_type_id` AS `current_verify_type_id`,`vmd`.`submit` AS `submit`,`vmd`.`title` AS `title`,`vmd`.`content` AS `content`,`vmd`.`remarks` AS `remarks`,`vmd`.`verify_first_role_name` AS `verify_first_role_name`,`vmd`.`verify_second_role_name` AS `verify_second_role_name`,`vmd`.`verify_third_role_name` AS `verify_third_role_name`,`vmd`.`verify_fourth_role_name` AS `verify_fourth_role_name`,`vmd`.`verify_fifth_role_name` AS `verify_fifth_role_name`,(case when (`vmd`.`current_verify_type_id` > `vmd`.`verify_type_id`) then NULL when (`vmd`.`current_verify_type_id` = 2) then `vmd`.`verify_first_role_name` when (`vmd`.`current_verify_type_id` = 3) then `vmd`.`verify_second_role_name` when (`vmd`.`current_verify_type_id` = 4) then `vmd`.`verify_third_role_name` when (`vmd`.`current_verify_type_id` = 5) then `vmd`.`verify_fourth_role_name` when (`vmd`.`current_verify_type_id` = 6) then `vmd`.`verify_fifth_role_name` else NULL end) AS `current_role_name`,(`vmd`.`current_verify_type_id` > `vmd`.`verify_type_id`) AS `is_all_verified`,`vmd`.`period_id` AS `period_id`,`vmd`.`period_index` AS `period_index`,`vmd`.`begin_time` AS `begin_time`,`vmd`.`end_time` AS `end_time`,`vmd`.`relation_id` AS `diary_relation_id`,`vmd`.`table_name` AS `diary_table_name`,`vmd`.`internship_name` AS `internship_name`,`vmd`.`internship_post_code` AS `internship_post_code`,`vmd`.`internship_post_name` AS `internship_post_name`,`vmd`.`internship_post_remarks` AS `internship_post_remarks`,`vmd`.`post_company_name` AS `post_company_name`,`vmd`.`title_id` AS `title_id`,`vmd`.`title_name` AS `title_name`,`vmd`.`teacher_id` AS `teacher_id`,`vmd`.`teacher_name` AS `teacher_name`,`vmd`.`student_id` AS `student_id`,`vmd`.`student_name` AS `student_name`,`vmd`.`school_id` AS `school_id`,`vmd`.`student_phone` AS `student_phone`,`vmd`.`student_department_name` AS `student_department_name`,`vmd`.`student_account` AS `student_account`,`vmd`.`student_major_name` AS `student_major_name` from (((`internship`.`main_verify_process` `mvp` join (select `internship`.`main_verify_process`.`relation_id` AS `relation_id`,max(`internship`.`main_verify_process`.`id`) AS `max_id` from `internship`.`main_verify_process` where ((`internship`.`main_verify_process`.`table_name` = 'MainDiary') and (`internship`.`main_verify_process`.`is_deleted` = 0)) group by `internship`.`main_verify_process`.`relation_id`) `latest` on((`mvp`.`id` = `latest`.`max_id`))) join `internship`.`view_main_diary` `vmd` on((`mvp`.`relation_id` = `vmd`.`id`))) left join `internship`.`base_user` `bu_create` on((`mvp`.`create_user_id` = `bu_create`.`ID`))) where ((`mvp`.`is_deleted` = 0) and (`mvp`.`table_name` = 'MainDiary'));

