DROP VIEW IF EXISTS `view_verify_main_diary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_verify_main_diary` AS select `mvp`.`id` AS `id`,`mvp`.`create_time` AS `create_time`,`mvp`.`is_deleted` AS `is_deleted`,`mvp`.`update_time` AS `update_time`,`mvp`.`relation_id` AS `relation_id`,`mvp`.`create_user_id` AS `create_user_id`,`mvp`.`verify_user_id` AS `verify_user_id`,`mvp`.`is_audit` AS `is_audit`,`mvp`.`reason` AS `reason`,`mvp`.`table_name` AS `table_name`,(select group_concat(`bu`.`name` separator '，') from `internship`.`base_user` `bu` where find_in_set(`bu`.`ID`,replace(`mvp`.`verify_user_id`,'|',','))) AS `verify_user_name`,`bu_create`.`name` AS `create_user_name`,`vmd`.`verify_type_id` AS `verify_type_id`,`vmd`.`verify_first_role_id` AS `verify_first_role_id`,`vmd`.`verify_second_role_id` AS `verify_second_role_id`,`vmd`.`verify_third_role_id` AS `verify_third_role_id`,`vmd`.`verify_fourth_role_id` AS `verify_fourth_role_id`,`vmd`.`verify_fifth_role_id` AS `verify_fifth_role_id`,`vmd`.`current_verify_type_id` AS `current_verify_type_id`,`vmd`.`submit` AS `submit`,`vmd`.`title` AS `title`,`vmd`.`remarks` AS `remarks`,`vmd`.`verify_first_role_name` AS `verify_first_role_name`,`vmd`.`verify_second_role_name` AS `verify_second_role_name`,`vmd`.`verify_third_role_name` AS `verify_third_role_name`,`vmd`.`verify_fourth_role_name` AS `verify_fourth_role_name`,`vmd`.`verify_fifth_role_name` AS `verify_fifth_role_name`,`vmd`.`period_id` AS `period_id`,`vmd`.`period_index` AS `period_index`,`vmd`.`begin_time` AS `begin_time`,`vmd`.`end_time` AS `end_time`,`vmd`.`relation_id` AS `diary_relation_id`,`vmd`.`table_name` AS `diary_table_name`,`vmd`.`internship_name` AS `internship_name`,`vmd`.`internship_post_name` AS `internship_post_name`,`vmd`.`post_company_name` AS `post_company_name`,`vmd`.`title_id` AS `title_id`,`vmd`.`title_name` AS `title_name`,`vmd`.`teacher_id` AS `teacher_id`,`vmd`.`teacher_name` AS `teacher_name`,`vmd`.`student_id` AS `student_id`,`vmd`.`student_name` AS `student_name`,`vmd`.`student_account` AS `student_account`,`vmd`.`school_id` AS `school_id`,`vmd`.`student_department_name` AS `student_department_name` from ((`internship`.`main_verify_process` `mvp` join `internship`.`view_main_diary` `vmd` on((`mvp`.`relation_id` = `vmd`.`id`))) left join `internship`.`base_user` `bu_create` on((`mvp`.`create_user_id` = `bu_create`.`ID`))) where ((`mvp`.`is_deleted` = 0) and (`mvp`.`table_name` = 'MainDiary'));

