-- View structure for view_external_internship_college_stats
-- ----------------------------
DROP VIEW IF EXISTS `view_external_internship_college_stats`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `view_external_internship_college_stats` AS select `vmi`.`id` AS `internship_id`,`vmi`.`name` AS `internship_name`,`vmi`.`create_time` AS `internship_create_time`,`bit`.`university_id` AS `department_id`,(select count(distinct `m`.`user_id`) from (`internship`.`view_verify_process_rel_intership_user_merge` `m` join `internship`.`view_base_user` `u` on((`u`.`ID` = `m`.`user_id`))) where ((`m`.`internship_id` = `vmi`.`id`) and (`m`.`is_deleted` = 0) and (`m`.`job_code` = 'STUDENT') and (`department_getCollegeId`(`u`.`DEPARTMENT_ID`) = `bit`.`university_id`))) AS `signup_student_count`,(select count(distinct `m`.`user_id`) from (`internship`.`view_verify_process_rel_intership_user_merge` `m` join `internship`.`view_base_user` `u` on((`u`.`ID` = `m`.`user_id`))) where ((`m`.`internship_id` = `vmi`.`id`) and (`m`.`is_deleted` = 0) and (`m`.`job_code` = 'SCHOOL_TEACHER') and (`department_getCollegeId`(`u`.`DEPARTMENT_ID`) = `bit`.`university_id`))) AS `signup_teacher_count`,(select count(distinct `vmip1`.`internship_post_id`) from `internship`.`view_verify_process_internship_post_merge` `vmip1` where ((`vmip1`.`internship_id` = `vmi`.`id`) and (`vmip1`.`is_deleted` = 0) and (`vmip1`.`is_audit` = 1) and (`vmip1`.`internship_post_id` is not null) and ((`vmip1`.`internship_post_code` <> 'SELF_INTERNSHIP') or isnull(`vmip1`.`internship_post_code`)))) AS `post_signup_count`,coalesce((select sum(`agg`.`ap`) from (select `vmip`.`internship_id` AS `internship_id`,`vmip`.`internship_post_id` AS `internship_post_id`,max(`vmip`.`all_person_num`) AS `ap` from `internship`.`view_verify_process_internship_post_merge` `vmip` where ((`vmip`.`is_deleted` = 0) and (`vmip`.`is_audit` = 1) and (`vmip`.`internship_post_id` is not null) and ((`vmip`.`internship_post_code` <> 'SELF_INTERNSHIP') or isnull(`vmip`.`internship_post_code`))) group by `vmip`.`internship_id`,`vmip`.`internship_post_id`) `agg` where (`agg`.`internship_id` = `vmi`.`id`)),0) AS `total_recruitment_headcount`,(select count(distinct `vmip3`.`internship_post_id`) from `internship`.`view_verify_process_internship_post_merge` `vmip3` where ((`vmip3`.`internship_id` = `vmi`.`id`) and (`vmip3`.`is_deleted` = 0) and (`vmip3`.`is_audit` in (-(1),0)) and (`vmip3`.`internship_post_id` is not null) and ((`vmip3`.`internship_post_code` <> 'SELF_INTERNSHIP') or isnull(`vmip3`.`internship_post_code`)))) AS `pending_audit_post_count`,(select count(distinct `s`.`student_id`) from `internship`.`view_verify_process_rel_stu_internship_post_merge` `s` where ((`s`.`internship_id` = `vmi`.`id`) and (`s`.`is_deleted` = 0) and (`department_getCollegeId`(`s`.`DEPARTMENT_ID`) = `bit`.`university_id`) and (`s`.`student_id` is not null) and (trim(`s`.`student_id`) <> ''))) AS `student_with_post_selection_count` from (`internship`.`view_main_internship` `vmi` join `internship`.`base_internship_type` `bit` on(((`bit`.`id` = `vmi`.`internship_type_id`) and (`bit`.`is_deleted` = 0)))) where ((`vmi`.`is_deleted` = 0) and (`vmi`.`int_type_name` = '校外实习') and (`bit`.`university_id` is not null) and (`bit`.`university_id` > 0));

-- ----------------------------


-- Function structure for department_getAllParentNames
-- ----------------------------
DROP FUNCTION IF EXISTS `department_getAllParentNames`;
delimiter ;;
CREATE FUNCTION `department_getAllParentNames`(nodeId int)
 RETURNS varchar(1000) CHARSET utf8
  DETERMINISTIC
BEGIN
    DECLARE parentList VARCHAR(1000);      # 返回父节点结果集
    DECLARE tempParent INTEGER;      # 临时存放父节点
		DECLARE tempName VARCHAR(50);      # 临时存放父节点

    SET parentList = '';
    SET tempParent = nodeId;
		SET tempName = '';

		SET @tabName = 'base_department';


    WHILE tempParent is not NULL DO        # 循环，用于查询节点上所有的父节点
			IF tempName<>'' THEN
				IF parentList<>'' THEN
					SET parentList = CONCAT(tempName,'/', parentList);
				ELSE
					SET parentList = tempName;
				END IF;
			END IF;
			SET tempName = (SELECT name FROM base_department where id=tempParent);   # 查询节点上所有父节点
      SET tempParent = (SELECT parent_id FROM base_department where id=tempParent);   # 查询节点上所有父节点
    END WHILE;
    RETURN parentList;       # 将返回结果处理，截取掉结果集前面的逗号
END
;;
delimiter ;

-- ----------------------------
-- Function structure for department_getCollegeId
-- ----------------------------
DROP FUNCTION IF EXISTS `department_getCollegeId`;
delimiter ;;
CREATE FUNCTION `department_getCollegeId`(`nodeid` int)
 RETURNS int(11)
  DETERMINISTIC
BEGIN
    DECLARE tempID INTEGER;
    DECLARE parentId INTEGER;
    DECLARE currentLevel INTEGER;

    IF nodeid IS NULL OR nodeid <= 0 THEN
        RETURN 0;
    END IF;

    SET tempID = nodeid;
    SET currentLevel = (SELECT `the_level` FROM `base_department`
                        WHERE `ID` = tempID AND `IS_DELETED` = 0);

    IF currentLevel IS NULL THEN
        RETURN 0;
    END IF;

    WHILE currentLevel > 2 AND tempID IS NOT NULL DO
        SET parentId = (SELECT `PARENT_ID` FROM `base_department`
                        WHERE `ID` = tempID AND `IS_DELETED` = 0);
        IF parentId IS NULL OR parentId = -1 THEN
            RETURN 0;
        END IF;
        SET tempID = parentId;
        SET currentLevel = (SELECT `the_level` FROM `base_department`
                            WHERE `ID` = tempID AND `IS_DELETED` = 0);
        IF currentLevel IS NULL THEN
            RETURN 0;
        END IF;
    END WHILE;

    RETURN IF(currentLevel = 2, tempID, 0);
END
;;
delimiter ;

-- ----------------------------
-- Function structure for department_getSchoolId
-- ----------------------------
DROP FUNCTION IF EXISTS `department_getSchoolId`;
delimiter ;;
CREATE FUNCTION `department_getSchoolId`(`nodeid` integer)
 RETURNS int(11)
  DETERMINISTIC
BEGIN
    DECLARE tempID INTEGER;
    DECLARE parentId INTEGER;
    DECLARE currentLevel INTEGER; -- 改为更清晰的变量名

    SET tempID = nodeid;
    -- 先获取当前节点的层级
    SET currentLevel = (SELECT the_level FROM base_department WHERE id = tempID);

    -- 循环条件：当前节点层级>1（未找到school节点），且存在父节点
    WHILE currentLevel > 1 AND tempID IS NOT NULL DO
        -- 查询当前节点的父节点ID
        SET parentId = (SELECT parent_id FROM base_department WHERE id = tempID);
        -- 查询父节点的层级
        SET currentLevel = (SELECT the_level FROM base_department WHERE id = parentId);
        -- 父节点作为下一次循环的当前节点
        SET tempID = parentId;
    END WHILE;

    -- 最终返回theLevel=1的节点ID（即schoolId）；若未找到则返回0
    RETURN IF(currentLevel = 1, tempID, 0);
END
;;
delimiter ;

-- ----------------------------
-- Function structure for department_isUnder
-- ----------------------------
DROP FUNCTION IF EXISTS `department_isUnder`;
delimiter ;;
CREATE FUNCTION `department_isUnder`(childId INT, ancestorId INT)
 RETURNS tinyint(1)
  DETERMINISTIC
BEGIN
    DECLARE tempId INT;
    IF childId IS NULL OR ancestorId IS NULL OR childId <= 0 OR ancestorId <= 0 THEN
        RETURN 0;
    END IF;
    SET tempId = childId;
    WHILE tempId IS NOT NULL DO
        IF tempId = ancestorId THEN
            RETURN 1;
        END IF;
        SET tempId = (SELECT `PARENT_ID` FROM `base_department`
                      WHERE `ID` = tempId AND `IS_DELETED` = 0 LIMIT 1);
    END WHILE;
    RETURN 0;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table main_internship_post
-- ----------------------------
DROP TRIGGER IF EXISTS `trg_cap_now_person_num`;
delimiter ;;
CREATE TRIGGER `trg_cap_now_person_num` BEFORE UPDATE ON `main_internship_post` FOR EACH ROW BEGIN
      IF NEW.now_person_num IS NOT NULL
         AND NEW.all_person_num IS NOT NULL
         AND NEW.now_person_num > NEW.all_person_num THEN
          SET NEW.now_person_num = NEW.all_person_num;
      END IF;
  END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
